  {% if product.brand %}{{ product.brand.name|escape }}{% endif %}
  {% if product.sku %}{{ product.sku|escape }}{% endif %}
  {% if product.sku|length == 13 or product.sku|length == 12 %}{{ product.sku }}{% endif %}
  {% with cats=product.categories.all %}
  {% if cats %}
  {% with cat=cats.0 %}
  {% for anc in cat.get_ancestors %}{{ anc.name|escape }} > {% endfor %}{{ cat.name|escape }}
  {% endwith %}
  {% endif %}
  {% endwith %}

